            ]

    if args.json:
        json.dump(rows, sys.stdout, indent=2)
        sys.stdout.write("\n")
        return 0

    for row in rows:
        if args.migration_map or (
            args.migration_status and not args.machine and "source_path" in row
        ):
            status = row.get("status", "")
            action = row.get("action", "")
            src = row.get("source_path", "?")
